import{_ as l,o as i,c as e,a3 as r}from"./chunks/framework.CS9vaShW.js";const c=JSON.parse('{"title":"金融与经济类博客写作指导","description":"","frontmatter":{},"headers":[],"relativePath":"public/prompt/博客/文章模板/金融.md","filePath":"public/prompt/博客/文章模板/金融.md","lastUpdated":1784075578000}'),t={name:"public/prompt/博客/文章模板/金融.md"};function o(p,a,h,n,d,s){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="金融与经济类博客写作指导" tabindex="-1">金融与经济类博客写作指导 <a class="header-anchor" href="#金融与经济类博客写作指导" aria-label="Permalink to &quot;金融与经济类博客写作指导&quot;">​</a></h1><h2 id="文章定位" tabindex="-1">文章定位 <a class="header-anchor" href="#文章定位" aria-label="Permalink to &quot;文章定位&quot;">​</a></h2><p>金融与经济类博客用于把当前聊天中讨论过的金融知识、经济概念、宏观机制、市场现象或个人学习理解，整理成一篇可复盘的学习笔记。</p><p>文章内容必须主要来自当前聊天上下文。模板只规定归纳方式和文章结构，不主动扩展无关主题，不把聊天中没有讨论过的内容强行写进文章。</p><p>文章不是投资建议，不追求确定性结论。重点是把讨论内容整理清楚，让以后回看时能快速理解当时讨论了什么、形成了什么理解、还有什么问题没有解决。</p><h2 id="开头摘要与图片位置要求" tabindex="-1">开头摘要与图片位置要求 <a class="header-anchor" href="#开头摘要与图片位置要求" aria-label="Permalink to &quot;开头摘要与图片位置要求&quot;">​</a></h2><p>文章开头不要直接放图片，必须先写一段简短的文章描述。</p><p>开头描述用于 VitePress 首页文章列表和读者快速判断文章主题，应为纯文本段落，不要包含 Markdown 图片、HTML 图片标签或其他会在概览中暴露的图片标记。</p><p>开头描述应控制在 1 段，简明说明：</p><ul><li>文章讨论的主题</li><li>想解决的核心问题</li><li>文章的主要分析方向</li></ul><p>描述之后再放汇总图片。</p><p>汇总图片用于概括全文，读者看图就应该能知道文章主要讨论什么。</p><p>图片应根据聊天内容提炼，不需要覆盖所有细节，重点呈现：</p><ul><li>主题</li><li>核心问题</li><li>关键概念</li><li>主要逻辑关系</li><li>一句简短总结</li></ul><p>适合使用信息卡片、流程图、逻辑关系图、对比图或简洁示意图。</p><h2 id="正文配图要求" tabindex="-1">正文配图要求 <a class="header-anchor" href="#正文配图要求" aria-label="Permalink to &quot;正文配图要求&quot;">​</a></h2><p>文章应图文并茂，但图片不必多。</p><p>只有当图片能帮助解释聊天中讨论过的概念、链条、对比关系、示例或数据变化时才使用。不要为了凑图而加图。</p><h2 id="推荐文章结构" tabindex="-1">推荐文章结构 <a class="header-anchor" href="#推荐文章结构" aria-label="Permalink to &quot;推荐文章结构&quot;">​</a></h2><h3 id="_1-讨论背景" tabindex="-1">1. 讨论背景 <a class="header-anchor" href="#_1-讨论背景" aria-label="Permalink to &quot;1. 讨论背景&quot;">​</a></h3><p>说明这篇文章来自当前聊天中的什么问题或讨论。</p><p>重点回答：为什么会聊到这个主题？当时想弄清楚什么？</p><h3 id="_2-核心问题" tabindex="-1">2. 核心问题 <a class="header-anchor" href="#_2-核心问题" aria-label="Permalink to &quot;2. 核心问题&quot;">​</a></h3><p>把聊天内容压缩成一个或几个核心问题。</p><p>问题要具体，不要泛泛而谈。</p><h3 id="_3-关键概念" tabindex="-1">3. 关键概念 <a class="header-anchor" href="#_3-关键概念" aria-label="Permalink to &quot;3. 关键概念&quot;">​</a></h3><p>整理聊天中真正用到的关键金融或经济概念。</p><p>只解释理解文章必需的概念，不要扩展成百科式介绍。</p><h3 id="_4-逻辑框架" tabindex="-1">4. 逻辑框架 <a class="header-anchor" href="#_4-逻辑框架" aria-label="Permalink to &quot;4. 逻辑框架&quot;">​</a></h3><p>把聊天中的分析过程整理成清晰链条。</p><p>可以按照以下方式组织：</p><ul><li>因果链条</li><li>变量关系</li><li>前提条件</li><li>适用场景</li><li>可能失效的情况</li></ul><p>这一部分是文章重点，目标是让读者看懂“为什么是这样”。</p><h3 id="_5-示例或场景" tabindex="-1">5. 示例或场景 <a class="header-anchor" href="#_5-示例或场景" aria-label="Permalink to &quot;5. 示例或场景&quot;">​</a></h3><p>如果聊天中出现了案例、类比、市场现象或假设场景，可以整理成一个简短示例。</p><p>示例只用于帮助理解逻辑，不用于给出操作建议。</p><h3 id="_6-个人理解" tabindex="-1">6. 个人理解 <a class="header-anchor" href="#_6-个人理解" aria-label="Permalink to &quot;6. 个人理解&quot;">​</a></h3><p>总结这次讨论后形成的理解。</p><p>可以包括：</p><ul><li>原来不清楚或容易误解的地方</li><li>现在更清楚的逻辑</li><li>仍然没有完全解决的问题</li><li>后续可以继续研究的方向</li></ul><h3 id="_7-风险提示" tabindex="-1">7. 风险提示 <a class="header-anchor" href="#_7-风险提示" aria-label="Permalink to &quot;7. 风险提示&quot;">​</a></h3><p>文章结尾保留简短提示：</p><blockquote><p>本文仅为个人学习笔记和讨论整理，不构成任何投资建议。金融市场和经济运行都存在不确定性，任何交易和投资决策都应基于独立判断和风险承受能力。</p></blockquote><h2 id="写作原则" tabindex="-1">写作原则 <a class="header-anchor" href="#写作原则" aria-label="Permalink to &quot;写作原则&quot;">​</a></h2><ul><li>先依据聊天内容确定文章主题，再选择合适结构组织内容</li><li>开头先写纯文本描述，再放汇总图片，避免 VitePress 首页文章列表显示图片标签</li><li>不逐字复刻聊天记录，要提炼、归纳、重组</li><li>不主动补写聊天中没有讨论过的大段内容</li><li>不写成百科词条，也不写成市场预测</li><li>不给出直接操作建议</li><li>篇幅不要太长，优先保证清晰、可复盘</li><li>开头描述负责概览，首图负责总览，正文负责解释逻辑</li></ul>',45)])])}const _=l(t,[["render",o]]);export{c as __pageData,_ as default};
